// Input Validation & Normalization
// Validates incoming data and normalizes it into a standard structure

const items = $input.all();

// Check if we have input
if (!items || items.length === 0) {
  return [{
    json: {
      error: true,
      message: "No input data received",
      timestamp: new Date().toISOString()
    }
  }];
}

const inputData = items[0].json;

// Extract contract data if present
const contractData = inputData.contract || {};

// Define mandatory fields
const mandatoryFields = ['request_id', 'trigger_type', 'sku_list', 'current_stock', 'mode'];

// Check for missing mandatory fields
const missingFields = mandatoryFields.filter(field => !inputData[field]);

if (missingFields.length > 0) {
  return [{
    json: {
      error: true,
      message: `Missing mandatory fields: ${missingFields.join(', ')}`,
      missing_fields: missingFields,
      timestamp: new Date().toISOString()
    }
  }];
}

// Generate UUID for operations_id
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Normalize SKU list into standard structure
function normalizeSKUList(skuList) {
  if (Array.isArray(skuList)) {
    return skuList.map(sku => {
      if (typeof sku === 'string') {
        return { sku_code: sku };
      }
      return {
        sku_code: sku.sku_code || sku.sku || sku.code,
        quantity: sku.quantity || null,
        priority: sku.priority || 'normal'
      };
    });
  }
  return [];
}

// Extract caller workflow from execution metadata
const callerWorkflow = $execution.customData?.caller_workflow || 
                       $execution.mode === 'manual' ? 'manual_trigger' : 'unknown';

// Build normalized output
const normalizedData = {
  operations_id: generateUUID(),
  request_id: inputData.request_id || contractData.request_id,
  trigger_type: inputData.trigger_type,
  sku_list: normalizeSKUList(inputData.sku_list),
  current_stock: inputData.current_stock,
  mode: inputData.mode || contractData.mode,
  approval_required: false,
  caller_workflow: callerWorkflow,
  timestamp: new Date().toISOString(),
  validation_status: 'passed',
  // Pass through optional fields if present
  warehouse_location: inputData.warehouse_location || null,
  priority_level: inputData.priority_level || 'normal',
  additional_context: inputData.additional_context || {},
  // Include contract fields in normalized output
  contract: {
    confidence: contractData.confidence || null,
    risk_level: contractData.risk_level || null,
    contract_valid: contractData.contract_valid || null,
    validation_timestamp: contractData.validation_timestamp || null
  }
};

return [{ json: normalizedData }];

