// Stock Monitor & Reorder Decision Logic
// Compares current stock levels against safety stock thresholds
// Factors in demand forecasts and determines reorder requirements

const workflowConfig = $('Workflow Configuration').first().json;
const inputData = $('Input Validation & Normalization').first().json;
const demandForecast = $('Demand Forecasting Agent').first().json;
const supplyChainData = $('Supply Chain Intelligence Agent').first().json;

// Extract configuration parameters
const safetyStockThreshold = workflowConfig.safety_stock_threshold || 0.2; // 20% default
const reorderBufferMultiplier = workflowConfig.reorder_buffer_multiplier || 1.5;
const highRiskDelayDays = workflowConfig.high_risk_delay_days || 14;

// Extract current stock from Input Validation & Normalization
const currentStock = inputData.current_stock || {};

// Extract demand forecast data - forecast_30d contains the 30-day forecast
const forecast30d = demandForecast.forecast_30d || {};

// Initialize results array
const skuAnalysis = [];
let overallReorderRequired = false;
let highestUrgency = 'none';

// Process each SKU in current stock
for (const [sku, stockData] of Object.entries(currentStock)) {
  // Handle both object format {quantity: X, max_capacity: Y} and simple number format
  const currentLevel = typeof stockData === 'object' ? (stockData.quantity || stockData.current_quantity || 0) : stockData;
  const maxCapacity = typeof stockData === 'object' ? (stockData.max_capacity || currentLevel * 3) : currentLevel * 3;

  // Get 30-day forecast for this SKU and calculate daily demand
  const forecast30dForSku = forecast30d[sku] || 0;
  const forecastedDailyDemand = forecast30dForSku / 30; // Convert 30-day forecast to daily demand

  // Calculate stock percentage
  const stockPercentage = maxCapacity > 0 ? currentLevel / maxCapacity : 0;

  // Calculate days of stock remaining
  const daysOfStockRemaining = forecastedDailyDemand > 0 
    ? currentLevel / forecastedDailyDemand 
    : 999; // If no demand, assume plenty of stock

  // Determine if reorder is required
  let reorderRequired = false;
  let urgencyLevel = 'none';
  let reason = '';

  // Check against critical threshold (below 10% or less than 3 days stock)
  if (stockPercentage <= 0.1 || daysOfStockRemaining <= 3) {
    reorderRequired = true;
    urgencyLevel = 'high';
    reason = `Critical stock level: ${(stockPercentage * 100).toFixed(1)}% remaining, only ${daysOfStockRemaining.toFixed(1)} days of stock`;
  }
  // Check against safety threshold
  else if (stockPercentage <= safetyStockThreshold || daysOfStockRemaining <= 7) {
    reorderRequired = true;
    urgencyLevel = 'medium';
    reason = `Below safety stock: ${(stockPercentage * 100).toFixed(1)}% remaining, ${daysOfStockRemaining.toFixed(1)} days of stock`;
  }
  // Check if approaching threshold
  else if (stockPercentage <= safetyStockThreshold * 1.5 || daysOfStockRemaining <= 14) {
    reorderRequired = true;
    urgencyLevel = 'low';
    reason = `Approaching safety threshold: ${(stockPercentage * 100).toFixed(1)}% remaining, ${daysOfStockRemaining.toFixed(1)} days of stock`;
  }
  else {
    reason = `Stock levels adequate: ${(stockPercentage * 100).toFixed(1)}% remaining, ${daysOfStockRemaining.toFixed(1)} days of stock`;
  }

  // Track overall reorder status
  if (reorderRequired) {
    overallReorderRequired = true;

    // Update highest urgency level
    if (urgencyLevel === 'high') {
      highestUrgency = 'high';
    } else if (urgencyLevel === 'medium' && highestUrgency !== 'high') {
      highestUrgency = 'medium';
    } else if (urgencyLevel === 'low' && highestUrgency === 'none') {
      highestUrgency = 'low';
    }
  }

  // Add SKU analysis to results
  skuAnalysis.push({
    sku: sku,
    current_stock: currentLevel,
    max_capacity: maxCapacity,
    stock_percentage: stockPercentage,
    forecast_30d: forecast30dForSku,
    forecasted_daily_demand: forecastedDailyDemand,
    days_of_stock_remaining: daysOfStockRemaining,
    reorder_required: reorderRequired,
    urgency_level: urgencyLevel,
    reason: reason
  });
}

// Sort by urgency (high -> medium -> low -> none)
const urgencyOrder = { 'high': 0, 'medium': 1, 'low': 2, 'none': 3 };
skuAnalysis.sort((a, b) => urgencyOrder[a.urgency_level] - urgencyOrder[b.urgency_level]);

// Prepare output
const output = {
  reorder_required: overallReorderRequired,
  overall_urgency: highestUrgency,
  sku_analysis: skuAnalysis,
  total_skus_analyzed: skuAnalysis.length,
  skus_requiring_reorder: skuAnalysis.filter(s => s.reorder_required).length,
  analysis_timestamp: new Date().toISOString(),
  configuration: {
    safety_stock_threshold: safetyStockThreshold,
    reorder_buffer_multiplier: reorderBufferMultiplier,
    high_risk_delay_days: highRiskDelayDays
  }
};

console.log('Stock Monitor Analysis Complete:', {
  reorder_required: overallReorderRequired,
  urgency: highestUrgency,
  skus_needing_reorder: output.skus_requiring_reorder
});

return [{ json: output }];

