  finalBlockedBy = 'CREA';
  blockReason = 'CREA decision must be respected';

  console.log('⛔ CREA BLOCK ENFORCED');
  console.log('CREA Approval:', creaApproval);
  console.log('Blocked By:', blockedBy);
  console.log('Block Reason:', blockReason);
