  decision_summary = currentData.message || 'CFO requested revision';
} else if (currentData.status === 'advisory') {
  status = 'advisory';
  decision_summary = currentData.message || 'No action required';
} else if (currentData.status === 'executed') {
  status = 'executed';
  decision_summary = 'Operations executed successfully';
  execution_performed = true;
