// Audit Trail Logger - Immutable Audit Record Creation
// Creates comprehensive audit trail for all WF-3 operations

const items = $input.all();
const inputData = items[0]?.json || {};

// Extract data from previous nodes
const validationData = $('Input Validation & Normalization').first()?.json || {};
const workflowConfig = $('Workflow Configuration').first()?.json || {};
const contractValidation = $('Contract Valid?').first()?.json || {};
const confidenceCheck = $('System Confidence Re-Check').first()?.json || {};
const founderGate = $('Founder Availability Gate').first()?.json || {};
const creaBlock = $('CREA Block Respect').first()?.json || {};
const executionLock = $('Hard Execution Lock - Pre-Operations').first()?.json || {};
const executionGate = $('Execution Allowed?').first()?.json || {};
const supplyChainData = $('Supply Chain Intelligence Agent').first()?.json || {};
const stockMonitor = $('Stock Monitor & Reorder Decision').first()?.json || {};
const cfoApproval = $('Request CFO Approval (WF-2)').first()?.json || {};

// Extract key identifiers
const request_id = validationData.request_id || inputData.request_id || 'UNKNOWN';
const operations_id = validationData.operations_id || inputData.operations_id || 'UNKNOWN';
const mode = validationData.mode || inputData.mode || 'simulation';

// Extract confidence and risk metrics
const confidence_score = confidenceCheck.confidence_score || inputData.confidence_score || null;
const risk_level = supplyChainData.risk_level || inputData.risk_level || 'unknown';

// Extract safety gate results
const founder_available = founderGate.founder_available !== undefined ? founderGate.founder_available : inputData.founder_available;
const crea_approval = creaBlock.crea_approved !== undefined ? creaBlock.crea_approved : inputData.crea_approval;
const contract_valid = contractValidation.contract_valid !== undefined ? contractValidation.contract_valid : true;
const execution_allowed = executionGate.execution_allowed !== undefined ? executionGate.execution_allowed : false;

// Determine execution status and reason
let execution_status = 'not_executed';
let execution_reason = '';

if (mode === 'execute' && execution_allowed) {
  execution_status = 'executed';
  execution_reason = 'All safety gates passed, execution mode enabled';
} else if (mode === 'simulation') {
  execution_status = 'simulated';
  execution_reason = 'Workflow running in simulation mode';
} else if (!contract_valid) {
  execution_status = 'blocked_contract';
  execution_reason = 'Contract validation failed';
} else if (!founder_available) {
  execution_status = 'blocked_founder';
  execution_reason = 'Founder not available for approval';
} else if (!crea_approval) {
  execution_status = 'blocked_crea';
  execution_reason = 'CREA approval not granted';
} else if (!execution_allowed) {
  execution_status = 'blocked_execution_lock';
  execution_reason = 'Hard execution lock prevented operations';
} else {
  execution_status = 'blocked_unknown';
  execution_reason = 'Execution blocked for unknown reason';
}

// Compile decision points
const decision_points = {
  contract_validation: {
    passed: contract_valid,
    timestamp: contractValidation.timestamp || new Date().toISOString()
  },
  confidence_check: {
    score: confidence_score,
    passed: confidence_score >= 0.7,
    timestamp: confidenceCheck.timestamp || new Date().toISOString()
  },
  founder_availability: {
    available: founder_available,
    timestamp: founderGate.timestamp || new Date().toISOString()
  },
  crea_approval: {
    approved: crea_approval,
    timestamp: creaBlock.timestamp || new Date().toISOString()
  },
  reorder_required: {
    required: stockMonitor.reorder_required || false,
    urgency: stockMonitor.overall_urgency || 'none',
    timestamp: stockMonitor.analysis_timestamp || new Date().toISOString()
  },
  cfo_approval: {
    status: cfoApproval.status || 'not_requested',
    approved: cfoApproval.status === 'approved',
    timestamp: cfoApproval.timestamp || new Date().toISOString()
  },
  execution_lock: {
    allowed: execution_allowed,
    timestamp: executionLock.timestamp || new Date().toISOString()
  }
};

// Compile safety gate results
const safety_gates = {
  contract_valid: contract_valid,
  confidence_adequate: confidence_score >= 0.7,
  founder_available: founder_available,
  crea_approved: crea_approval,
  execution_allowed: execution_allowed,
  all_gates_passed: contract_valid && confidence_score >= 0.7 && founder_available && crea_approval && execution_allowed
};

// Create immutable audit record
const auditRecord = {
  // Core identifiers
  audit_id: `AUDIT-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  request_id: request_id,
  operations_id: operations_id,
  workflow_id: $workflow.id,
  workflow_name: $workflow.name,
  execution_id: $execution.id,

  // Execution metadata
  performed_by: 'WF-3',
  timestamp: new Date().toISOString(),
  mode: mode,

  // Risk and confidence metrics
  confidence_score: confidence_score,
  risk_level: risk_level,

  // Safety gate status
  founder_available: founder_available,
  crea_approval: crea_approval,
  contract_valid: contract_valid,
  execution_allowed: execution_allowed,

  // Execution status
  execution_status: execution_status,
  execution_reason: execution_reason,

  // Decision points (detailed)
  decision_points: decision_points,

  // Safety gates summary
  safety_gates: safety_gates,

  // Operational data
  reorder_required: stockMonitor.reorder_required || false,
  skus_analyzed: stockMonitor.total_skus_analyzed || 0,
  skus_requiring_reorder: stockMonitor.skus_requiring_reorder || 0,
  cfo_approval_status: cfoApproval.status || 'not_requested',

  // Immutability marker
  immutable: true,
  audit_version: '1.0',

  // Original input data (for reference)
  original_input: {
    request_id: request_id,
    trigger_type: validationData.trigger_type,
    sku_list: validationData.sku_list,
    mode: mode
  }
};

// Log audit record
console.log('=== IMMUTABLE AUDIT RECORD CREATED ===');
console.log(JSON.stringify(auditRecord, null, 2));

// Return audit record
return [{ json: auditRecord }];

